<template>

	<view class="change-pass">

		<view class="header" v-if="type ==1 ">
			<text class="">
				您是否还记得账号
				<text class="mobile">{{userinfo.username}}</text>
			</text>
			<view class="">
				当前使用的登录密码
			</view>
		</view>
		<view class="btn-box" v-if="type ==1 ">
			<view class="btn default" @click="goForGet">
				不记得
			</view>
			<view class="btn primary" @click="$util.on('/pages/ucenter_sub/change?type=password')">
				记得
			</view>
		</view>


		<view class="header" v-if="type ==2 ">
			<text class="">
				您是否还记得账号
				<text class="mobile">{{userinfo.username}}</text>
			</text>
			<view class="">
				当前使用的交易密码
			</view>
		</view>

		<view class="btn-box" v-if="type ==2 ">
			<view class="btn default" @click="goForGet">
				不记得
			</view>
			<view class="btn primary" @click="$util.on('/pages/ucenter_sub/change?type=trader_password')">
				记得
			</view>
		</view>
	</view>

</template>

<script>
	export default {
		data() {
			return {
				list: [],
				title: '',
				type: '',

				user: {
					company: '',
					qq: '',
					email: '',
					password: '',
					trader_password: '',
				}
			}
		},
		onLoad(e) {
			this.type = e.type
			switch (e.type) {
				case '1':
					this.title = '修改登录密码'
					break;
				case '2':
					this.title = '修改支付密码'
					break;
			}


			uni.setNavigationBarTitle({
				title: this.title
			})



		},
		methods: {
			goForGet() {

				if (!this.userinfo.mobile || this.userinfo.mobile == '') {
					this.$util.on('/pages/ucenter_sub/bind_mobile?type=1')
					return;
				}

				switch (this.type) {
					case '1':
						this.$util.on('/pages/ucenter_sub/forget_pass?type=1')
						break;
					case '2':
						this.$util.on('/pages/ucenter_sub/forget_pass?type=2')
						break;
				}

			},
			loadData() {
				// this.$u.api.ucenterset({})
				// 	.then(res => {
				// 		this.list = res
				// 	}).catch(res => {})
			},
			checkFrom() {
				switch (this.type) {
					case 'company':

						break;
					case 'qq':

						this.$util.msg('请填写正确QQ号')
						return /^[1-9][0-9]{4,10}$/.test(this.user[this.type]);
						break;
					case 'wx':


						break;
					case 'email':
						this.$util.msg('请填写正确邮箱')
						return /[\w!#$%&'*+/=?^_`{|}~-]+(?:\.[\w!#$%&'*+/=?^_`{|}~-]+)*@(?:[\w](?:[\w-]*[\w])?\.)+[\w](?:[\w-]*[\w])?/
							.test(this.user[this.type]);
						break;

				}
				return true;
			},
			async save() {

				if (!this.user[this.type]) {
					this.$util.msg('请填写数据')
					return;
				}

				if (!this.checkFrom()) {
					return;
				}


				uni.showLoading({
					mask: true,
					title: '保存中...',

				})
				this.user.type = this.type


				await this.$u.api.userinfosave(this.user)
					.then(res => {

						if (this.type == 'password' || this.type == 'trader_password') {


						} else {
							this.$u.vuex('userinfo.' + this.type, res.data);
						}

						this.$util.msg('保存成功')

						setTimeout(() => {
							//注册成功前往首页
							this.$util.back();
						}, 1500)
					}).catch(res => {})

				uni.hideLoading()
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	page {
		background-color: #f5f7fa;
		word-wrap: break-word;
		line-height: 1.3;
		font-family: Regular, Droid Sans, Droid Sans Fallback, STHeiti, SimHei, Hei;
	}

	.change-pass {
		width: 100%;
		height: 100%;
		display: flex;
		align-items: center;
		justify-content: flex-start;
		flex-direction: column;
	}

	.header {
		width: 100%;
		height: 300rpx;
		background-color: #fff;
		display: flex;
		align-items: center;
		justify-content: center;
		flex-direction: column;
		font-size: 32rpx;
		color: #818282;
	}

	.header .mobile {
		color: #1e2331;
		font-weight: 550;
	}

	.change-pass .btn-box {
		display: flex;
		align-items: center;
		justify-content: center;
		gap: 30rpx;
		padding: 0 30rpx;
		margin-top: 66rpx;
	}

	.default {
		background: #FFFFFF;
		color: #1e2331;
	}

	.btn {
		width: 330rpx;
		height: 94rpx;
		border-radius: 48rpx;
		display: flex;
		align-items: center;
		justify-content: center;
		font-size: 30rpx;
	}

	.primary {
		background: linear-gradient(90deg, #FE8A56, #FF504B);
	
		color: #fff;
	}
</style>
